#!/data/data/com.termux/files/usr/bin/bash#=========================================================#  Termux-Doctor: Main Executable#  Unified interface for all diagnostics modules#=========================================================# Load core librariessource "./lib/colors.sh"source "./lib/logging.sh"source "./lib/utils.sh"source "./lib/branding.sh"# Load diagnostic modulessource "./lib/checks/system.sh"source "./lib/checks/storage.sh"source "./lib/checks/network.sh"source "./lib/checks/packages.sh"source "./lib/checks/environment.sh"#---------------------------------------------------------# Help Menu#---------------------------------------------------------show_help() {    doctor_banner    echo -e "${CYAN}Usage:${RESET}"    echo "  termux-doctor [option]"    echo    echo -e "${CYAN}Options:${RESET}"    echo "  --all           Run all diagnostics"    echo "  --system        Run system checks"    echo "  --storage       Run storage checks"    echo "  --network       Run network checks"    echo "  --packages      Run package checks"    echo "  --env           Run environment checks"    echo "  --help          Show this help menu"    echo}#---------------------------------------------------------# Argument Handler#---------------------------------------------------------case "$1" in    --all)        run_system_checks        run_storage_checks        run_network_checks        run_package_checks        run_environment_checks        ;;    --system)        run_system_checks        ;;    --storage)        run_storage_checks        ;;    --network)        run_network_checks        ;;    --packages)        run_package_checks        ;;    --env)        run_environment_checks        ;;    --help|"")        show_help        ;;    *)        err "Unknown option: $1"        show_help        ;;esac
